using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 renamed the discriminator property
        // from "Discriminator" to "$type". Preserve the old name so existing
        // documents are still recognized.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: EF Core 9 stores just the key as the JSON "id".
        // Previously it was "Discriminator|Key" (e.g. "Blog|1"). Preserve the
        // old format so existing documents are still addressable.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();

        // Breaking change 3: HasIndex() now throws for the Cosmos provider.
        // Remove it (Cosmos indexes are managed in the Azure portal).
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: Raw SQL queries referencing c.Discriminator must be
    // kept as-is since we preserved "Discriminator" above. If you had switched
    // to "$type", every raw query like:
    //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
    // would need to become:
    //   SELECT * FROM c WHERE c["$type"] = 'Blog'
}

// Value generator that reproduces the EF Core 8 "Discriminator|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

